function load(){
  try{
    const r=localStorage.getItem(STORE_KEY);
    if(r)data=JSON.parse(r);
    if(!data.kills)data.kills=[];if(!data.captures)data.captures=[];if(!data.deaths)data.deaths=[];
    if(!data.players)data.players=[];if(!data.trades)data.trades=[];if(!data.ptrades)data.ptrades=[];
    if(!data.mines)data.mines=[];if(!data.harvests)data.harvests=[];if(!data.bounties)data.bounties=[];if(!data.settings)data.settings={};if(!data.customThemes)data.customThemes=[];
    // Set default wheel logo if none saved
    if(!data.settings.orgLogo)data.settings.orgLogo=DEFAULT_LOGO;
    csUnlocked=data.settings.csUnlocked||false;
  }catch(e){data={kills:[],captures:[],deaths:[],players:[],trades:[],ptrades:[],mines:[],settings:{orgLogo:DEFAULT_LOGO},customThemes:[]};}
  buildPresetGrid();applyTheme();applyLogoToDOM();updateStats();
}
function save(){localStorage.setItem(STORE_KEY,JSON.stringify(data));}

// KONAMI CODE
document.addEventListener('keydown',function(e){
  // Allow Konami input regardless of focus (blur inputs briefly)
  konamiSeq.push(e.keyCode);
  if(konamiSeq.length>10)konamiSeq.shift();
  if(konamiSeq.length===10&&konamiSeq.every((v,i)=>v===konamiCode[i])){
    konamiSeq=[];
    if(!csUnlocked){
      csUnlocked=true;data.settings.csUnlocked=true;save();buildPresetGrid();
      document.getElementById('cs-logo').style.display='';
      document.getElementById('default-logo').style.display='none';
      toast('// ACCESS GRANTED — CROSS SECTION UNLOCKED','secret');
    } else {
      toast('// CROSS SECTION ALREADY UNLOCKED','secret');
    }
  }
  if(e.key==='Enter'&&document.activeElement===document.getElementById('l-name'))addLoot();
  if(e.key==='Enter'&&document.activeElement===document.getElementById('pt-item-inp'))addPTItem();
});

// AUTOCOMPLETE — focus-safe, Electron-compatible
function acFilter(inputId,listId,items){
  const inp=document.getElementById(inputId);
  const list=document.getElementById(listId);
  if(!inp||!list)return;
  const val=inp.value.toLowerCase();
  const matches=val?items.filter(i=>String(i).toLowerCase().includes(val)).slice(0,12):items.slice(0,12);
  if(!matches.length){list.classList.remove('open');return;}
  list.innerHTML=matches.map(m=>`<div class="ac-item">${String(m).replace(/</g,'&lt;')}</div>`).join('');
  list.classList.add('open');
  list.querySelectorAll('.ac-item').forEach((el,idx)=>{
    el.addEventListener('mousedown',function(e){e.preventDefault();});
    el.addEventListener('click',function(){
      inp.value=matches[idx];
      inp.dispatchEvent(new Event('input',{bubbles:true}));
      list.classList.remove('open');
      inp.focus();
    });
  });
}
function acFocus(inputId,listId,items){
  // Show dropdown immediately on focus even if field is empty
  acFilter(inputId,listId,items);
}
document.addEventListener('click',function(e){
  if(!e.target.closest('.ac-wrap'))document.querySelectorAll('.ac-list').forEach(l=>l.classList.remove('open'));
});
function playerNames(){return data.players.map(p=>p.name);}

// STARS (RSC)
function createStars(){
  if(starsCreated)return;
  const c=document.getElementById('stars-container');
  for(let i=0;i<200;i++){
    const s=document.createElement('div');s.className='star';
    const size=Math.random()*2.5+0.5;
    s.style.cssText=`width:${size}px;height:${size}px;left:${Math.random()*100}%;top:${Math.random()*100}%;animation:twinkle ${2+Math.random()*4}s ${Math.random()*4}s infinite;opacity:${0.3+Math.random()*0.7}`;
    c.appendChild(s);
  }starsCreated=true;
}
function removeStars(){document.getElementById('stars-container').innerHTML='';starsCreated=false;}

function applyTheme(preview){
  const s=preview||data.settings;
  const r=document.documentElement.style;

  // Start from the canonical Captain's Log defaults every time.
  // This prevents partial presets from leaving lighter/extra values behind.
  const base=DEFAULT_CL_THEME.c;
  const map={bg:'--bg',surf:'--surf',card:'--card',brd:'--brd',acc:'--acc',acc2:'--acc2',accd:'--accD',txt:'--txt',mut:'--mut'};
  Object.entries(map).forEach(([k,v])=>r.setProperty(v,s[k]||base[k]));

  // Always re-assert fixed semantic vars so they aren't lost on theme switch.
  r.setProperty('--grn','#28c870');
  r.setProperty('--red','#e03030');
  r.setProperty('--amber','#c08020');
  r.setProperty('--purple','#9050d0');

  // Reset all optional theme effects before applying the current theme.
  const th=s.theme||DEFAULT_CL_THEME.th;
  r.setProperty('--theme-scanlines',th.sc||'none');
  r.setProperty('--theme-header-extra',th.hd||'none');
  r.setProperty('--theme-bg-pattern',th.bgp||'none');
  r.setProperty('--head','Rajdhani,sans-serif');
  const ntGrid=document.getElementById('nt-grid');
  if(ntGrid)ntGrid.classList.toggle('active',!!th.nt);
  if(th.stars)createStars();else removeStars();

  if(!preview){
    const nm=s.orgname||"Captain's Log";
    document.getElementById('hdr-title').textContent=nm;
    document.getElementById('tb-title').textContent=(s.tbtitle||nm).toUpperCase().slice(0,18);
    if(s.subtitle)document.getElementById('hdr-sub').textContent='// '+s.subtitle.toUpperCase();
    document.getElementById('faction-tag').textContent=s.factiontag||'';
    const hndl=s.handle||'';document.getElementById('tb-handle').textContent=hndl?'[ '+hndl+' ]':'';
    applyLogoToDOM();
  }
}

function updateLogoColor(c){
  // Legacy call from applyTheme — update border to accent colour if no custom border set
  if(!data.settings.logoBorder){
    document.documentElement.style.setProperty('--logo-border', c);
    const fill=data.settings.logoFill||shadeColor(c,-60);
    document.documentElement.style.setProperty('--logo-fill', fill);
  }
}

function shadeColor(hex, pct){
  const n=parseInt(hex.replace('#',''),16),r=Math.min(255,Math.max(0,(n>>16)+pct)),g=Math.min(255,Math.max(0,((n>>8)&0xff)+pct)),b=Math.min(255,Math.max(0,(n&0xff)+pct));
  return '#'+[r,g,b].map(v=>v.toString(16).padStart(2,'0')).join('');
}

function applyLogoToDOM(){
  const s=data.settings;
  const fill=s.logoFill||'var(--accd)';
  const border=s.logoBorder||'var(--acc)';
  // Derive initials: use saved logoInitials, else first letters of org name words
  let initials=s.logoInitials;
  if(!initials||initials==='CS'){
    const name=s.orgname||"Captain's Log";
    initials=name.split(/\s+/).map(w=>w[0]).join('').toUpperCase().slice(0,3);
    if(!initials)initials='CL';
  }
  document.documentElement.style.setProperty('--logo-fill', fill);
  document.documentElement.style.setProperty('--logo-border', border);
  // Drive the logo-wrap border/bg directly so CSS vars take effect immediately
  const wrap=document.getElementById('logo-wrap');
  if(wrap){wrap.style.borderColor=border;wrap.style.background=fill;}
  // Inner display
  const img=document.getElementById('logo-img');
  const ini=document.getElementById('logo-initials');
  if(s.orgLogo&&img){img.src=s.orgLogo;img.style.display='';if(ini)ini.style.display='none';}
  else{if(img)img.style.display='none';if(ini){ini.textContent=initials;ini.style.color=border;ini.style.display='';}}
}

function updateLogoPreview(){
  const fill=document.getElementById('col-logo-fill')?.value||'#1a3a6a';
  const border=document.getElementById('col-logo-border')?.value||'#4488dd';
  const initials=(document.getElementById('set-logo-initials')?.value||'CS').toUpperCase()||'CS';
  const box=document.getElementById('logo-preview-box');
  const pImg=document.getElementById('logo-preview-img');
  const pIni=document.getElementById('logo-preview-initials');
  if(box){box.style.background=fill;box.style.borderColor=border;}
  if(pIni){pIni.textContent=initials;pIni.style.color=border;}
  // Also live-update the actual header logo
  document.documentElement.style.setProperty('--logo-fill',fill);
  document.documentElement.style.setProperty('--logo-border',border);
  const hdrDisplay=document.getElementById('logo-display');
  const hdrIni=document.getElementById('logo-initials');
  if(hdrDisplay){hdrDisplay.style.background=fill;hdrDisplay.style.borderColor=border;}
  if(hdrIni){hdrIni.textContent=initials;hdrIni.style.color=border;}
}

function triggerLogoUpload(){document.getElementById('logo-file-input').click();}

function handleLogoUpload(input){
  const file=input.files[0];
  if(!file)return;
  if(file.size>2*1024*1024){toast('Image too large — max 2MB','err');return;}
  const reader=new FileReader();
  reader.onload=function(e){
    const b64=e.target.result;
    // Show in preview
    const pImg=document.getElementById('logo-preview-img');
    const pIni=document.getElementById('logo-preview-initials');
    if(pImg){pImg.src=b64;pImg.style.display='';}
    if(pIni)pIni.style.display='none';
    // Store temporarily
    window._pendingLogo=b64;
    // Live update header
    const hImg=document.getElementById('logo-img');
    const hIni=document.getElementById('logo-initials');
    if(hImg){hImg.src=b64;hImg.style.display='';}
    if(hIni)hIni.style.display='none';
    toast('Logo loaded — save settings to keep');
  };
  reader.readAsDataURL(file);
}

function clearLogo(){
  window._pendingLogo=null;
  data.settings.orgLogo=null;
  save();
  const pImg=document.getElementById('logo-preview-img');
  const pIni=document.getElementById('logo-preview-initials');
  if(pImg){pImg.src='';pImg.style.display='none';}
  if(pIni)pIni.style.display='';
  const hImg=document.getElementById('logo-img');
  const hIni=document.getElementById('logo-initials');
  if(hImg){hImg.src='';hImg.style.display='none';}
  if(hIni)hIni.style.display='';
  toast('Logo cleared');
}

function logoCycles(){
  const clicks=(window._logoClicks=(window._logoClicks||0)+1);
  clearTimeout(window._logoTimer);
  if(clicks>=7&&csUnlocked){
    applyPreset('cs');toast('Cross Section preset applied','secret');
  }
  window._logoTimer=setTimeout(()=>window._logoClicks=0,2000);
}

function buildPresetGrid(){
  const entries=Object.entries(PRESETS).filter(([k])=>k!=='cs'||csUnlocked);
  document.getElementById('preset-grid').innerHTML=entries.map(([k,p])=>
    `<button class="preset-btn" onclick="applyPreset('${k}')"><div class="pb-swatch" style="background:linear-gradient(to right,${p.sw[0]},${p.sw[1]})"></div><div class="pb-name" style="color:${p.sw[0]}">${p.name}</div><div class="pb-sub">${p.tag}</div></button>`).join('');
}

function applyPreset(key){
  const p=PRESETS[key];if(!p)return;
  const map={bg:'col-bg',surf:'col-surf',card:'col-card',brd:'col-brd',acc:'col-acc',acc2:'col-acc2',accd:'col-accd',txt:'col-txt',mut:'col-mut'};
  Object.entries(map).forEach(([k,id])=>{const el=document.getElementById(id);if(el&&p.c[k])el.value=p.c[k];});
  document.getElementById('set-orgname').value=p.name;
  document.getElementById('set-subtitle').value=p.sub;
  document.getElementById('set-tbtitle').value=p.name.toUpperCase().slice(0,18);
  window._pendingTheme=p.th;window._pendingFactionTag=p.tag;
  // Apply logo preset colours
  if(p.logo){
    const lf=document.getElementById('col-logo-fill');
    const lb=document.getElementById('col-logo-border');
    const li=document.getElementById('set-logo-initials');
    if(lf)lf.value=p.logo.fill;
    if(lb)lb.value=p.logo.border;
    if(li)li.value=p.logo.initials;
    window._pendingLogoFill=p.logo.fill;
    window._pendingLogoBorder=p.logo.border;
    window._pendingLogoInitials=p.logo.initials;
    // Live update logo
    const wrap=document.getElementById('logo-wrap');
    const ini=document.getElementById('logo-initials');
    if(wrap){wrap.style.background=p.logo.fill;wrap.style.borderColor=p.logo.border;}
    if(ini){ini.textContent=p.logo.initials;ini.style.color=p.logo.border;}
    // Update preview box in settings
    const pBox=document.getElementById('logo-preview-box');
    const pIni=document.getElementById('logo-preview-initials');
    if(pBox){pBox.style.background=p.logo.fill;pBox.style.borderColor=p.logo.border;}
    if(pIni){pIni.textContent=p.logo.initials;pIni.style.color=p.logo.border;}
  }
  // Immediately update header text so it matches the colour preview
  document.getElementById('hdr-title').textContent=p.name;
  document.getElementById('hdr-sub').textContent='// '+p.sub.toUpperCase();
  document.getElementById('faction-tag').textContent=p.tag;
  document.getElementById('tb-title').textContent=p.name.toUpperCase().slice(0,18);
  livePreview();
  toast('Preset loaded — save to apply','warn');
}

function livePreview(){
  const acc=document.getElementById('col-acc')?.value||'#4488dd';
  const acc2=document.getElementById('col-acc2')?.value||'#66aaff';
  const bar=document.getElementById('preview-bar');if(bar)bar.style.background=`linear-gradient(to right,${acc},${acc2})`;
  ['bg','surf','card','brd','acc','acc2','accd','txt','mut'].forEach(k=>{
    const el=document.getElementById('col-'+k);const vEl=document.getElementById('col-'+k+'-val');
    if(el&&vEl)vEl.textContent=el.value;
  });
  // Live apply to page
  const preview={};
  ['bg','surf','card','brd','acc','acc2','accd','txt','mut'].forEach(k=>{
    const el=document.getElementById('col-'+k);if(el)preview[k]=el.value;
  });
  preview.theme=window._pendingTheme||data.settings.theme||{};
  applyTheme(preview);
}

function showSettingsTab(t){
  document.querySelectorAll('.settings-section').forEach(s=>s.classList.remove('active'));
  document.querySelectorAll('.settings-nav-btn').forEach(b=>b.classList.remove('active'));
  document.getElementById('st-'+t)?.classList.add('active');
  document.querySelectorAll('.settings-nav-btn').forEach(b=>{if(b.textContent.toLowerCase().includes(t.slice(0,4)))b.classList.add('active');});
}

function saveCustomTheme(){
  const name=document.getElementById('ct-name').value.trim()||'Custom Theme';
  const theme={name,bg:document.getElementById('col-bg').value,surf:document.getElementById('col-surf').value,card:document.getElementById('col-card').value,brd:document.getElementById('col-brd').value,acc:document.getElementById('col-acc').value,acc2:document.getElementById('col-acc2').value,accd:document.getElementById('col-accd').value,txt:document.getElementById('col-txt').value,mut:document.getElementById('col-mut').value,theme:window._pendingTheme||{}};
  if(!data.customThemes)data.customThemes=[];
  data.customThemes.push(theme);save();renderSavedThemes();toast('Custom theme saved');
}

function renderSavedThemes(){
  const list=document.getElementById('saved-themes-list');if(!list)return;
  if(!data.customThemes?.length){list.innerHTML='<div style="color:var(--mut);font-family:var(--mono);font-size:11px">No saved themes yet</div>';return;}
  list.innerHTML=data.customThemes.map((t,i)=>`<div class="saved-theme-row"><div class="st-swatch" style="background:linear-gradient(to right,${t.acc},${t.acc2||t.acc})"></div><div class="st-name">${t.name}</div><button class="btn-s" style="font-size:10px;padding:3px 8px" onclick="loadCustomTheme(${i})">Load</button><button class="btn-d" style="font-size:10px" onclick="delCustomTheme(${i})">x</button></div>`).join('');
}

function loadCustomTheme(i){
  const t=data.customThemes[i];if(!t)return;
  const map={bg:'col-bg',surf:'col-surf',card:'col-card',brd:'col-brd',acc:'col-acc',acc2:'col-acc2',accd:'col-accd',txt:'col-txt',mut:'col-mut'};
  Object.entries(map).forEach(([k,id])=>{const el=document.getElementById(id);if(el&&t[k])el.value=t[k];});
  window._pendingTheme=t.theme||{};livePreview();toast('Custom theme loaded','warn');
}
function delCustomTheme(i){data.customThemes.splice(i,1);save();renderSavedThemes();toast('Theme deleted');}

function showTab(t){
  ['trading','ptrade','mining','harvesting','kills','captures','deaths','career','players','bounties'].forEach(id=>{
    document.getElementById('v-'+id).style.display=t===id?'block':'none';
    document.getElementById('t-'+id).classList.toggle('active',t===id);
  });
  SFX.tab();
  if(t==='career')renderCareer();if(t==='players')renderPlayers();
  if(t==='captures'){renderCaptures();renderLocStats();}
  if(t==='kills')renderKills();if(t==='trading')renderTrades();
  if(t==='deaths')renderDeaths();if(t==='ptrade')renderPTrades();
  if(t==='mining')renderMines();if(t==='harvesting')renderHarvests();
  if(t==='bounties')renderBounties();
}

function updateStats(){
  const kills=data.kills.length,deaths=data.deaths.length,kd=deaths>0?(kills/deaths).toFixed(2):(kills>0?kills+'.00':'0.00');
  document.getElementById('st-kills').textContent=kills;document.getElementById('st-deaths').textContent=deaths;
  document.getElementById('st-kd').textContent=kd;document.getElementById('st-caps').textContent=data.captures.length;
  document.getElementById('st-bounties').textContent=data.bounties.filter(b=>b.status==='complete').length+'/'+data.bounties.length;
  document.getElementById('st-players').textContent=data.players.length;
  document.getElementById('st-profit').textContent=fmtA(calcTotalProfit());
  if(kills>0){const f={};data.kills.forEach(k=>f[k.method||k.ktype]=(f[k.method||k.ktype]||0)+1);const t=Object.entries(f).sort((a,b)=>b[1]-a[1])[0];document.getElementById('st-topmethod').textContent=t?'FAV: '+t[0].toUpperCase():'';}
}

function calcCommProfit(){return data.trades.filter(t=>t.sellPrice>0&&t.sellLoc).reduce((s,t)=>s+((t.sellPrice-t.buyPrice)*t.qty),0);}
function calcPTradeProfit(){return data.ptrades.filter(t=>t.sellPrice>0&&t.soldTo).reduce((s,t)=>s+(t.sellPrice-(t.buyPrice||0)),0);}
function calcTotalProfit(){return calcCommProfit()+calcPTradeProfit();}
function fmtA(n){if(Math.abs(n)>=1000000)return(n/1000000).toFixed(1)+'M';if(Math.abs(n)>=1000)return(n/1000).toFixed(1)+'K';return Math.round(n).toString();}
function threatLevel(name){if(!name)return null;const n=name.toLowerCase().trim();const p=data.players.find(x=>(x.cat==='hostile'||x.cat==='highthreat')&&x.name.toLowerCase().trim()===n);return p?p.cat:null;}
function fmtDate(iso){const d=new Date(iso);return d.toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'})+' '+d.toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit'});}
function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}

// KILL TYPE
function setKillType(t){killType=t;document.getElementById('kt-ship').classList.toggle('active',t==='ship');document.getElementById('kt-fps').classList.toggle('active',t==='fps');document.getElementById('k-ship-fields').style.display=t==='ship'?'':'none';document.getElementById('k-fps-fields').style.display=t==='fps'?'':'none';}

// DEATH TYPE
function setDeathType(t){
  deathType=t;
  ['pvpship','pvpfps','pveship','pvefps','crash','env','bugcig'].forEach(x=>{document.getElementById('dt-'+x).classList.toggle('active',t===x);document.getElementById('d-'+x+'-fields').style.display=t===x?'':'none';});
}

// KILLS
function submitKill(){
  let entry={id:Date.now(),ktype:killType,date:new Date().toISOString()};
  if(killType==='ship'){
    const pilot=document.getElementById('k-pilot').value.trim();if(!pilot){toast('Target pilot required','err');return;}
    entry={...entry,pilot,org:document.getElementById('k-org').value.trim(),ship:document.getElementById('k-ship').value.trim(),shipClass:document.getElementById('k-sclass').value,method:document.getElementById('k-method').value,location:document.getElementById('k-loc').value.trim(),notes:document.getElementById('k-notes').value.trim()};
    ['k-pilot','k-org','k-ship','k-loc','k-notes'].forEach(id=>document.getElementById(id).value='');
  }else{
    const pilot=document.getElementById('kf-pilot').value.trim();if(!pilot){toast('Target pilot required','err');return;}
    entry={...entry,pilot,org:document.getElementById('kf-org').value.trim(),weapon:document.getElementById('kf-weapon').value.trim(),loctype:document.getElementById('kf-loctype').value,location:document.getElementById('kf-loc').value.trim(),theirArmour:document.getElementById('kf-armour').value.trim(),method:'fps',notes:document.getElementById('kf-notes').value.trim()};
    ['kf-pilot','kf-org','kf-weapon','kf-loc','kf-armour','kf-notes'].forEach(id=>document.getElementById(id).value='');
  }
  data.kills.unshift(entry);save();updateStats();renderKills();toast('Kill confirmed');
}

function renderKills(){
  const list=document.getElementById('kill-list'),q=(document.getElementById('ks-search').value||'').toLowerCase(),tf=document.getElementById('ks-type').value,mf=document.getElementById('ks-method').value;
  let fil=data.kills.filter(k=>(!tf||k.ktype===tf)&&(!mf||k.method===mf)&&(!q||(k.pilot||'').toLowerCase().includes(q)||(k.ship||'').toLowerCase().includes(q)||(k.location||'').toLowerCase().includes(q)||(k.weapon||'').toLowerCase().includes(q)));
  document.getElementById('kill-count').textContent='('+fil.length+' of '+data.kills.length+')';
  if(!fil.length){list.innerHTML='<div class="empty"><div class="empty-icon">+</div>'+(data.kills.length?'NO MATCHES':'NO KILLS LOGGED YET')+'</div>';return;}
  list.innerHTML=fil.map(k=>{
    const open=expK[k.id],tl=threatLevel(k.pilot);
    const badge=tl==='highthreat'?'<span class="threat-badge">HIGH THREAT</span>':tl==='hostile'?'<span class="flagged-badge">HOSTILE</span>':'';
    const isFps=k.ktype==='fps';
    return`<div class="cc kill-card${tl?' flagged':''}"><div class="ch${open?' open':''}" onclick="togK(${k.id})"><div class="ch-l"><span class="xi${open?' open':''}" id="xi-k-${k.id}">&#9658;</span><div style="min-width:0"><div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap"><span class="sname kill-name">${esc(k.pilot)}</span>${isFps?'<span class="method-badge m-fps">FPS</span>':(k.ship?`<span class="cbadge ${BCLASS[k.shipClass]||'b-other'}">${esc(k.ship)}</span>`:'')}${k.method&&!isFps?`<span class="method-badge ${METHODS[k.method]||'m-other'}">${k.method}</span>`:''}${badge}</div><div class="cid">${k.org?esc(k.org)+' // ':''} ${k.location?esc(k.location):''}${isFps&&k.weapon?' // '+esc(k.weapon):''}</div></div></div><div class="cm"><span class="cd">${fmtDate(k.date)}</span></div></div>
    <div class="cb${open?' open':''}" id="cb-k-${k.id}"><div class="detail-grid">
    ${isFps?`<div class="ditem"><span class="dlabel">Target</span><span class="dval" style="color:var(--red)">${esc(k.pilot)}</span></div><div class="ditem"><span class="dlabel">Org</span><span class="dval">${k.org?esc(k.org):'&mdash;'}</span></div><div class="ditem"><span class="dlabel">Weapon</span><span class="dval">${k.weapon?esc(k.weapon):'&mdash;'}</span></div><div class="ditem"><span class="dlabel">Location</span><span class="dval">${k.location?esc(k.location):'&mdash;'}</span></div><div class="ditem"><span class="dlabel">Location Type</span><span class="dval">${k.loctype||'&mdash;'}</span></div><div class="ditem"><span class="dlabel">Their Armour</span><span class="dval">${k.theirArmour?esc(k.theirArmour):'&mdash;'}</span></div>`:`<div class="ditem"><span class="dlabel">Target</span><span class="dval" style="color:var(--red)">${esc(k.pilot)}</span></div><div class="ditem"><span class="dlabel">Org</span><span class="dval">${k.org?esc(k.org):'&mdash;'}</span></div><div class="ditem"><span class="dlabel">Ship</span><span class="dval">${k.ship?esc(k.ship)+' ('+k.shipClass+')':'&mdash;'}</span></div><div class="ditem"><span class="dlabel">Method</span><span class="dval"><span class="method-badge ${METHODS[k.method]||'m-other'}">${k.method}</span></span></div><div class="ditem"><span class="dlabel">Location</span><span class="dval">${k.location?esc(k.location):'&mdash;'}</span></div>`}
    </div>${k.notes?`<div class="sect">// Notes</div><div class="notes-txt">${esc(k.notes)}</div>`:''}<div class="card-actions"><button class="btn-s" onclick="addKillToPlayer(${JSON.stringify(k.pilot).replace(/</g,'&lt;')},event)">Add to Contacts</button><button class="btn-d" onclick="delKill(${k.id})">Delete</button></div></div></div>`;
  }).join('');
}
function togK(id){expK[id]=!expK[id];const b=document.getElementById('cb-k-'+id),x=document.getElementById('xi-k-'+id);if(b){b.classList.toggle('open',expK[id]);b.previousElementSibling.classList.toggle('open',expK[id]);}if(x)x.classList.toggle('open',expK[id]);}
function delKill(id){data.kills=data.kills.filter(k=>k.id!==id);save();updateStats();renderKills();SFX.delete();toast('Kill removed');}
function addKillToPlayer(name,e){e.stopPropagation();document.getElementById('p-name').value=name;document.getElementById('p-met').value='Encountered in combat';showTab('players');toast('Contact pre-filled','warn');}

// CAPTURES
function addLoot(){const n=document.getElementById('l-name').value.trim(),q=parseInt(document.getElementById('l-qty').value)||1,c=document.getElementById('l-cat').value;if(!n)return;lootItems.push({name:n,qty:q,cat:c});document.getElementById('l-name').value='';document.getElementById('l-qty').value='1';renderLootTags();document.getElementById('l-name').focus();}
function removeLoot(i){lootItems.splice(i,1);renderLootTags();}
function renderLootTags(){document.getElementById('loot-tags').innerHTML=lootItems.map((l,i)=>`<span class="ltag"><span class="qty">x${l.qty}</span><span class="cat ${CATS[l.cat]||'cat-other'}">${l.cat}</span><span class="nm">${esc(l.name)}</span><span class="rm" onclick="removeLoot(${i})">x</span></span>`).join('');}
function submitCapture(){
  const ship=document.getElementById('c-ship').value.trim();if(!ship){toast('Ship name required','err');return;}
  data.captures.unshift({id:Date.now(),ship,shipClass:document.getElementById('c-class').value,location:document.getElementById('c-loc').value.trim(),crew:document.getElementById('c-crew').value.trim(),snare:document.getElementById('c-snare').value,success:document.getElementById('c-success').value,loot:[...lootItems],notes:document.getElementById('c-notes').value.trim(),date:new Date().toISOString()});
  save();updateStats();renderCaptures();renderLocStats();['c-ship','c-loc','c-crew','c-notes'].forEach(id=>document.getElementById(id).value='');document.getElementById('c-class').value='freighter';lootItems=[];renderLootTags();toast('Capture logged');
}
function renderLocStats(){
  const el=document.getElementById('loc-stats');if(!el)return;
  const locs={};data.captures.forEach(c=>{if(c.location){if(!locs[c.location])locs[c.location]={total:0,full:0};locs[c.location].total++;if(c.success==='full')locs[c.location].full++;}});
  const sorted=Object.entries(locs).sort((a,b)=>b[1].total-a[1].total).slice(0,5);
  el.innerHTML=sorted.map(([loc,s])=>`<span style="margin-right:12px">${esc(loc)}: <span style="color:var(--grn)">${s.full}</span>/<span style="color:var(--mut)">${s.total}</span></span>`).join('')||'No location data yet';
}
function renderCaptures(){
  const list=document.getElementById('cap-list'),q=(document.getElementById('cs-search').value||'').toLowerCase(),cf=document.getElementById('cs-class').value,sf=document.getElementById('cs-success').value;
  let fil=data.captures.filter(c=>(!cf||c.shipClass===cf)&&(!sf||c.success===sf)&&(!q||c.ship.toLowerCase().includes(q)||(c.location||'').toLowerCase().includes(q)||c.loot.some(l=>l.name.toLowerCase().includes(q))));
  document.getElementById('cap-count').textContent='('+fil.length+' of '+data.captures.length+')';
  if(!fil.length){list.innerHTML='<div class="empty"><div class="empty-icon">X</div>'+(data.captures.length?'NO MATCHES':'NO CAPTURES LOGGED YET')+'</div>';return;}
  const successColors={full:'var(--grn)',partial:'var(--amber)',escaped:'var(--mut)',loss:'var(--red)'};
  list.innerHTML=fil.map(c=>{const open=expC[c.id],tq=c.loot.reduce((s,l)=>s+l.qty,0);const lh=c.loot.length?c.loot.map(l=>`<span class="ltag"><span class="qty">x${l.qty}</span><span class="cat ${CATS[l.cat]||'cat-other'}">${l.cat}</span><span class="nm">${esc(l.name)}</span></span>`).join(''):'<span style="color:var(--mut);font-size:11px;font-family:var(--mono)">No loot</span>';
  const scol=successColors[c.success]||'var(--mut)';
  return`<div class="cc"><div class="ch${open?' open':''}" onclick="togC(${c.id})"><div class="ch-l"><span class="xi${open?' open':''}" id="xi-c-${c.id}">&#9658;</span><div style="min-width:0"><div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap"><span class="sname cap-name">${esc(c.ship)}</span><span class="cbadge ${BCLASS[c.shipClass]||'b-other'}">${c.shipClass}</span>${c.success?`<span style="font-size:10px;font-family:var(--mono);padding:1px 5px;border-radius:2px;color:${scol};border:1px solid ${scol};opacity:.8">${c.success}</span>`:''}</div><div class="cid">${c.location?esc(c.location)+' // ':''} ${tq} items${c.snare?' // '+c.snare:''}</div></div></div><div class="cm"><span class="cd">${fmtDate(c.date)}</span></div></div><div class="cb${open?' open':''}" id="cb-c-${c.id}"><div class="sect">// Loot (${tq} items)</div><div class="loot-grid">${lh}</div>${c.crew?`<div class="sect">// Crew</div><div class="notes-txt">${esc(c.crew)}</div>`:''} ${c.notes?`<div class="sect">// Notes</div><div class="notes-txt">${esc(c.notes)}</div>`:''}<div class="card-actions"><button class="btn-d" onclick="delCap(${c.id})">Delete</button></div></div></div>`;}).join('');
}
function togC(id){expC[id]=!expC[id];const b=document.getElementById('cb-c-'+id),x=document.getElementById('xi-c-'+id);if(b){b.classList.toggle('open',expC[id]);b.previousElementSibling.classList.toggle('open',expC[id]);}if(x)x.classList.toggle('open',expC[id]);}
function delCap(id){data.captures=data.captures.filter(c=>c.id!==id);save();updateStats();renderCaptures();SFX.delete();toast('Capture removed');}

// COMMODITY TRADING
function updateTradeCalc(){const qty=parseFloat(document.getElementById('tr-qty').value)||0,buy=parseFloat(document.getElementById('tr-buyprice').value)||0,sell=parseFloat(document.getElementById('tr-sellprice').value)||0,el=document.getElementById('tr-calc');if(qty>0&&buy>0&&sell>0){const p=(sell-buy)*qty;el.textContent=(p>=0?'+ ':'')+fmtA(p)+' aUEC';el.style.color=p>=0?'var(--grn)':'var(--red)';}else{el.textContent=qty>0&&buy>0?'Cost: '+fmtA(buy*qty)+' aUEC':'';el.style.color='var(--mut)';}}
['tr-qty','tr-buyprice','tr-sellprice'].forEach(id=>{const el=document.getElementById(id);if(el)el.addEventListener('input',updateTradeCalc);});
function submitTrade(){
  const commodity=document.getElementById('tr-commodity').value.trim();if(!commodity){toast('Commodity required','err');return;}
  const qty=parseFloat(document.getElementById('tr-qty').value)||0;if(!qty){toast('Quantity required','err');return;}
  const sellLoc=document.getElementById('tr-sellloc').value.trim(),sellPrice=parseFloat(document.getElementById('tr-sellprice').value)||0;
  data.trades.unshift({id:Date.now(),commodity,qty,buyPrice:parseFloat(document.getElementById('tr-buyprice').value)||0,buyLoc:document.getElementById('tr-buyloc').value.trim(),sellPrice:sellLoc?sellPrice:0,sellLoc,notes:document.getElementById('tr-notes').value.trim(),date:new Date().toISOString()});
  save();updateStats();renderTrades();['tr-commodity','tr-qty','tr-buyprice','tr-buyloc','tr-sellprice','tr-sellloc','tr-notes'].forEach(id=>document.getElementById(id).value='');document.getElementById('tr-calc').textContent='';toast('Trade logged');
}
function renderTrades(){
  const list=document.getElementById('trade-list'),q=(document.getElementById('trs-search').value||'').toLowerCase(),sf=document.getElementById('trs-filter').value;
  let fil=data.trades.filter(t=>{const mS=!sf||(sf==='sold'&&t.sellLoc&&t.sellPrice>0)||(sf==='pending'&&(!t.sellLoc||!t.sellPrice));const mQ=!q||t.commodity.toLowerCase().includes(q)||(t.buyLoc||'').toLowerCase().includes(q)||(t.sellLoc||'').toLowerCase().includes(q);return mS&&mQ;});
  const pend=data.trades.filter(t=>!t.sellLoc||!t.sellPrice).length;
  document.getElementById('tr-profit').textContent=fmtA(calcCommProfit());
  document.getElementById('ptr-profit').textContent=fmtA(calcPTradeProfit());
  document.getElementById('tr-routes').textContent=data.trades.length;document.getElementById('tr-pending').textContent=pend;
  document.getElementById('trade-count').textContent='('+fil.length+' of '+data.trades.length+')';
  if(!fil.length){list.innerHTML='<div class="empty"><div class="empty-icon">&#10227;</div>'+(data.trades.length?'NO MATCHES':'NO TRADES LOGGED YET')+'</div>';return;}
  list.innerHTML=fil.map(t=>{const open=expT[t.id],sold=t.sellLoc&&t.sellPrice>0,profit=sold?((t.sellPrice-t.buyPrice)*t.qty):null;const pb=profit!==null?`<span class="profit-badge ${profit>=0?'profit-pos':'profit-neg'}">${profit>=0?'+':''}${fmtA(profit)} aUEC</span>`:'<span class="pending-badge">PENDING</span>';
  return`<div class="cc trade-card"><div class="ch${open?' open':''}" onclick="togT(${t.id})"><div class="ch-l"><span class="xi${open?' open':''}" id="xi-t-${t.id}">&#9658;</span><div style="min-width:0"><div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap"><span class="sname trade-name">${esc(t.commodity)}</span><span style="font-family:var(--mono);font-size:11px;color:var(--mut)">x${t.qty} SCU</span>${pb}</div><div class="cid"><span>${t.buyLoc?esc(t.buyLoc):'?'}</span><span class="route-arrow">&#8594;</span><span>${t.sellLoc?esc(t.sellLoc):'UNSOLD'}</span></div></div></div><div class="cm"><span class="cd">${fmtDate(t.date)}</span></div></div><div class="cb${open?' open':''}" id="cb-t-${t.id}"><div class="detail-grid"><div class="ditem"><span class="dlabel">Commodity</span><span class="dval">${esc(t.commodity)}</span></div><div class="ditem"><span class="dlabel">Qty</span><span class="dval">${t.qty} SCU</span></div><div class="ditem"><span class="dlabel">Buy Price</span><span class="dval">${t.buyPrice?fmtA(t.buyPrice)+' /SCU':'&mdash;'}</span></div><div class="ditem"><span class="dlabel">Bought At</span><span class="dval">${t.buyLoc?esc(t.buyLoc):'&mdash;'}</span></div><div class="ditem"><span class="dlabel">Sell Price</span><span class="dval">${t.sellPrice?fmtA(t.sellPrice)+' /SCU':'UNSOLD'}</span></div><div class="ditem"><span class="dlabel">Sold At</span><span class="dval">${t.sellLoc?esc(t.sellLoc):'&mdash;'}</span></div></div>${profit!==null?`<div style="margin-top:8px;font-family:var(--mono);font-size:13px;color:${profit>=0?'var(--grn)':'var(--red)'}">NET: ${profit>=0?'+':''}${fmtA(profit)} aUEC</div>`:''} ${t.notes?`<div class="sect">// Notes</div><div class="notes-txt">${esc(t.notes)}</div>`:''}<div class="card-actions">${!sold?`<button class="btn-s" onclick="completeTrade(${t.id})">Mark as Sold</button>`:''}<button class="btn-d" onclick="delTrade(${t.id})">Delete</button></div></div></div>`;}).join('');
}
function togT(id){expT[id]=!expT[id];const b=document.getElementById('cb-t-'+id),x=document.getElementById('xi-t-'+id);if(b){b.classList.toggle('open',expT[id]);b.previousElementSibling.classList.toggle('open',expT[id]);}if(x)x.classList.toggle('open',expT[id]);}
function completeTrade(id){const t=data.trades.find(x=>x.id===id);if(!t)return;const price=prompt('Sell price per SCU (aUEC):'),loc=prompt('Sold at (location):');if(price&&loc){t.sellPrice=parseFloat(price)||0;t.sellLoc=loc;save();updateStats();renderTrades();toast('Trade completed');}}
function delTrade(id){data.trades=data.trades.filter(t=>t.id!==id);save();updateStats();renderTrades();SFX.delete();toast('Trade removed');}

// PLAYER TRADING
function setPTradeType(t){
  ptradeType=t;
  document.getElementById('pt-buy-btn').classList.toggle('active',t==='buy');
  document.getElementById('pt-sell-btn').classList.toggle('active',t==='sell');
  document.getElementById('pt-buy-fields').style.display=t==='buy'?'':'none';
  document.getElementById('pt-sell-fields').style.display=t==='sell'?'':'none';
}
function updatePTCalc(){
  const buy=parseFloat(document.getElementById('pt-buyprice')?.value)||0;
  const sell=parseFloat(document.getElementById('pt-sellprice')?.value)||0;
  const el=document.getElementById('pt-calc');
  if(!el)return;
  if(buy>0&&sell>0){const p=sell-buy;el.textContent=(p>=0?'+ ':'')+fmtA(p)+' aUEC';el.style.color=p>=0?'var(--grn)':'var(--red)';}
  else el.textContent='';
}
function addPTItem(){
  const name=document.getElementById('pt-item-inp').value.trim();
  if(!name){toast('Item name required','err');return;}
  const cat=document.getElementById('pt-item-cat').value;
  const qty=parseInt(document.getElementById('pt-item-qty').value)||1;
  ptItems.push({name,cat,qty});
  renderPTItemTags();
  document.getElementById('pt-item-inp').value='';
  document.getElementById('pt-item-qty').value='1';
  document.getElementById('pt-item-inp').focus();
}
function removePTItem(i){ptItems.splice(i,1);renderPTItemTags();}
function renderPTItemTags(){
  document.getElementById('pt-items-tags').innerHTML=ptItems.map((it,i)=>
    `<span class="pt-item-tag"><span class="pt-cat">${it.cat}</span>${it.qty>1?'<span style="color:var(--acc);margin:0 2px">x'+it.qty+'</span>':''} ${esc(it.name)} <span class="pt-rm" onclick="removePTItem(${i})">×</span></span>`
  ).join('');
}
function submitPTrade(){
  if(!ptItems.length){toast('Add at least one item','err');return;}
  const isBuy=ptradeType==='buy';
  const soldTo=document.getElementById('pt-soldto')?.value.trim()||'';
  const sellPrice=parseFloat(document.getElementById('pt-sellprice')?.value)||0;
  const buyFrom=document.getElementById('pt-buyfrom')?.value.trim()||'';
  const buyPrice=parseFloat(document.getElementById('pt-buyprice')?.value)||0;
  // Build display name from items
  const itemLabel=ptItems.length===1?ptItems[0].name:ptItems.length+' items';
  data.ptrades.unshift({
    id:Date.now(),
    item:itemLabel,
    items:[...ptItems],
    cat:ptItems[0]?.cat||'other',
    ptradeType,
    buyPrice:isBuy?buyPrice:0,
    buyFrom:isBuy?buyFrom:'',
    buyLoc:isBuy?(document.getElementById('pt-buyloc')?.value.trim()||''):'',
    sellPrice:!isBuy?sellPrice:0,
    soldTo:!isBuy?soldTo:'',
    sellLoc:!isBuy?(document.getElementById('pt-sellloc')?.value.trim()||''):'',
    notes:document.getElementById('pt-notes').value.trim(),
    date:new Date().toISOString()
  });
  save();updateStats();renderPTrades();
  ptItems=[];renderPTItemTags();
  ['pt-buyprice','pt-buyfrom','pt-buyloc','pt-sellprice','pt-soldto','pt-sellloc','pt-notes'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});
  document.getElementById('pt-calc').textContent='';
  toast('Player trade logged');
}
function renderPTrades(){
  const list=document.getElementById('ptrade-list'),q=(document.getElementById('pts-search').value||'').toLowerCase(),sf=document.getElementById('pts-filter').value;
  let fil=data.ptrades.filter(t=>{
    const isBuy=t.ptradeType==='buy'||(!t.ptradeType&&!!t.buyFrom);
    const mS=!sf||(sf==='buy'&&isBuy)||(sf==='sell'&&!isBuy);
    const itemsText=(t.items||[]).map(i=>i.name).join(' ').toLowerCase();
    const mQ=!q||t.item.toLowerCase().includes(q)||itemsText.includes(q)||(t.buyFrom||'').toLowerCase().includes(q)||(t.soldTo||'').toLowerCase().includes(q);
    return mS&&mQ;
  });
  document.getElementById('ptrade-count').textContent='('+fil.length+' of '+data.ptrades.length+')';
  if(!fil.length){list.innerHTML='<div class="empty"><div class="empty-icon">&#8652;</div>'+(data.ptrades.length?'NO MATCHES':'NO PLAYER TRADES LOGGED YET')+'</div>';return;}
  list.innerHTML=fil.map(t=>{
    const open=expPT[t.id];
    const isBuy=t.ptradeType==='buy'||(!t.ptradeType&&!!t.buyFrom);
    const price=isBuy?t.buyPrice:t.sellPrice;
    const partner=isBuy?t.buyFrom:t.soldTo;
    const partnerThreat=threatLevel(partner);
    // Item tags
    const itemHtml=(t.items&&t.items.length)?t.items.map(i=>`<span class="pt-item-tag"><span class="pt-cat">${i.cat}</span>${i.qty>1?'<span style="color:var(--acc);margin:0 2px">x'+i.qty+'</span>':''} ${esc(i.name)}</span>`).join(''):`<span class="pt-item-tag">${esc(t.item)}</span>`;
    return`<div class="cc ptrade-card" style="border-left:3px solid ${isBuy?'#1a3a6a':'#1a6a1a'}"><div class="ch${open?' open':''}" onclick="togPT(${t.id})"><div class="ch-l"><span class="xi${open?' open':''}" id="xi-pt-${t.id}">&#9658;</span><div style="min-width:0"><div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap"><span class="sname" style="color:${isBuy?'#66aaff':'var(--grn)'}">${esc(t.item)}</span><span class="cbadge" style="background:${isBuy?'#0a1a30':'#0a1a0a'};color:${isBuy?'#4488dd':'#28c870'};border:1px solid ${isBuy?'#1a3060':'#104a10'}">${isBuy?'BOUGHT':'SOLD'}</span>${price?`<span style="font-family:var(--mono);font-size:10px;color:var(--mut)">${fmtA(price)} aUEC</span>`:''}</div><div class="cid">${isBuy?'From: ':'To: '}${partner?esc(partner)+(partnerThreat?' ⚠':''):'—'}</div></div></div><div class="cm"><span class="cd">${fmtDate(t.date)}</span></div></div>
    <div class="cb${open?' open':''}" id="cb-pt-${t.id}">
    <div class="sect">// Items</div><div class="pt-items-list" style="margin-bottom:8px">${itemHtml}</div>
    <div class="detail-grid">
    <div class="ditem"><span class="dlabel">${isBuy?'Bought From':'Sold To'}</span><span class="dval">${partner?esc(partner)+(partnerThreat?' <span style="color:var(--red)">⚠ '+partnerThreat+'</span>':''):'&mdash;'}</span></div>
    <div class="ditem"><span class="dlabel">Price</span><span class="dval" style="color:${isBuy?'var(--amber)':'var(--grn)'}">${price?fmtA(price)+' aUEC':'&mdash;'}</span></div>
    <div class="ditem"><span class="dlabel">Location</span><span class="dval">${(isBuy?t.buyLoc:t.sellLoc)||'&mdash;'}</span></div>
    </div>${t.notes?`<div class="sect">// Notes</div><div class="notes-txt">${esc(t.notes)}</div>`:''}<div class="card-actions"><button class="btn-d" onclick="delPTrade(${t.id})">Delete</button></div></div></div>`;
  }).join('');
}
function togPT(id){expPT[id]=!expPT[id];const b=document.getElementById('cb-pt-'+id),x=document.getElementById('xi-pt-'+id);if(b){b.classList.toggle('open',expPT[id]);b.previousElementSibling.classList.toggle('open',expPT[id]);}if(x)x.classList.toggle('open',expPT[id]);}
function delPTrade(id){data.ptrades=data.ptrades.filter(t=>t.id!==id);save();updateStats();renderPTrades();SFX.delete();toast('Trade removed');}

// MINING
function submitMine(type){
  const g=(id)=>document.getElementById(id)?.value.trim()||'';
  const gn=(id)=>parseFloat(document.getElementById(id)?.value)||0;
  let entry={id:Date.now(),mtype:type,date:new Date().toISOString()};
  if(type==='hand')entry={...entry,location:g('hm-loc'),rock:g('hm-rock'),material:g('hm-mat'),yield:gn('hm-yield'),quality:gn('hm-quality'),value:gn('hm-value'),notes:g('hm-notes')};
  else if(type==='ground')entry={...entry,vehicle:g('gm-vehicle'),location:g('gm-loc'),rock:g('gm-rock'),material:g('gm-mat'),yield:gn('gm-yield'),quality:gn('gm-quality'),value:gn('gm-value'),notes:g('gm-notes')};
  else entry={...entry,ship:g('sm-ship'),location:g('sm-loc'),rock:g('sm-rock'),material:g('sm-mat'),yield:gn('sm-yield'),quality:gn('sm-quality'),instability:gn('sm-instab'),value:gn('sm-value'),notes:g('sm-notes')};
  if(!entry.material&&!entry.location){toast('At least location or material required','err');return;}
  data.mines.unshift(entry);save();updateStats();renderMines();
  document.querySelectorAll('#v-mining input,#v-mining textarea').forEach(el=>{if(el.type!=='button')el.value='';});
  toast('Mine logged');
}
function renderMines(){
  const list=document.getElementById('mine-list'),q=(document.getElementById('ms-search').value||'').toLowerCase(),tf=document.getElementById('ms-type').value;
  let fil=data.mines.filter(m=>(!tf||m.mtype===tf)&&(!q||(m.material||'').toLowerCase().includes(q)||(m.location||'').toLowerCase().includes(q)||(m.rock||'').toLowerCase().includes(q)));
  document.getElementById('mine-count').textContent='('+fil.length+' of '+data.mines.length+')';
  if(!fil.length){list.innerHTML='<div class="empty"><div class="empty-icon">&#9653;</div>'+(data.mines.length?'NO MATCHES':'NO MINING SESSIONS LOGGED YET')+'</div>';return;}
  const typeLabels={hand:'Hand',ground:'Ground Vehicle',ship:'Ship'};
  list.innerHTML=fil.map(m=>{const open=expM[m.id];return`<div class="cc mine-card"><div class="ch${open?' open':''}" onclick="togM(${m.id})"><div class="ch-l"><span class="xi${open?' open':''}" id="xi-m-${m.id}">&#9658;</span><div style="min-width:0"><div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap"><span class="sname mine-name">${esc(m.material||m.rock||'Unknown')}</span><span class="cbadge" style="background:#1a1000;color:#c87020;border:1px solid #3a2800">${typeLabels[m.mtype]||m.mtype}</span>${m.yield?`<span style="font-family:var(--mono);font-size:10px;color:var(--mut)">${m.yield} SCU</span>`:''}</div><div class="cid">${m.location?esc(m.location):''}${m.quality?' // Q: '+m.quality+'%':''}${m.value?' // ~'+fmtA(m.value)+' aUEC':''}</div></div></div><div class="cm"><span class="cd">${fmtDate(m.date)}</span></div></div>
  <div class="cb${open?' open':''}" id="cb-m-${m.id}"><div class="detail-grid">
  ${m.ship?`<div class="ditem"><span class="dlabel">Ship</span><span class="dval">${esc(m.ship)}</span></div>`:''}
  ${m.vehicle?`<div class="ditem"><span class="dlabel">Vehicle</span><span class="dval">${esc(m.vehicle)}</span></div>`:''}
  ${m.location?`<div class="ditem"><span class="dlabel">Location</span><span class="dval">${esc(m.location)}</span></div>`:''}
  ${m.rock?`<div class="ditem"><span class="dlabel">Rock Type</span><span class="dval">${esc(m.rock)}</span></div>`:''}
  ${m.material?`<div class="ditem"><span class="dlabel">Material</span><span class="dval">${esc(m.material)}</span></div>`:''}
  ${m.yield?`<div class="ditem"><span class="dlabel">Yield</span><span class="dval">${m.yield} SCU</span></div>`:''}
  ${m.quality?`<div class="ditem"><span class="dlabel">Quality</span><span class="dval">${m.quality}%</span></div>`:''}
  ${m.instability?`<div class="ditem"><span class="dlabel">Instability</span><span class="dval">${m.instability}%</span></div>`:''}
  ${m.value?`<div class="ditem"><span class="dlabel">Est. Value</span><span class="dval">${fmtA(m.value)} aUEC</span></div>`:''}
  </div>${m.notes?`<div class="sect">// Notes</div><div class="notes-txt">${esc(m.notes)}</div>`:''}<div class="card-actions"><button class="btn-d" onclick="delMine(${m.id})">Delete</button></div></div></div>`;}).join('');
}
function togM(id){expM[id]=!expM[id];const b=document.getElementById('cb-m-'+id),x=document.getElementById('xi-m-'+id);if(b){b.classList.toggle('open',expM[id]);b.previousElementSibling.classList.toggle('open',expM[id]);}if(x)x.classList.toggle('open',expM[id]);}
function delMine(id){data.mines=data.mines.filter(m=>m.id!==id);save();renderMines();SFX.delete();toast('Entry removed');}

// DEATHS
function submitDeath(){
  let entry={id:Date.now(),dtype:deathType,date:new Date().toISOString()};
  const g=(id)=>document.getElementById(id)?.value.trim()||'';
  if(deathType==='pvpship')entry={...entry,ship:g('dp-ship'),killer:g('dp-killer'),killerShip:g('dp-killerShip'),location:g('dp-loc'),notes:g('dp-notes')};
  else if(deathType==='pvpfps')entry={...entry,killer:g('df-killer'),weapon:g('df-weapon'),loadout:g('df-loadout'),location:g('df-loc'),notes:g('df-notes')};
  else if(deathType==='pveship')entry={...entry,ship:g('dve-ship'),enemy:g('dve-enemy'),enemyShip:g('dve-enemyship'),location:g('dve-loc'),notes:g('dve-notes')};
  else if(deathType==='pvefps')entry={...entry,enemy:g('dvf-enemy'),loadout:g('dvf-loadout'),location:g('dvf-loc'),notes:g('dvf-notes')};
  else if(deathType==='crash')entry={...entry,ship:g('dc-ship'),hit:g('dc-hit'),location:g('dc-loc'),notes:g('dc-notes')};
  else if(deathType==='env')entry={...entry,ship:g('de-ship'),hazard:document.getElementById('de-hazard')?.value||'other',location:g('de-loc'),notes:g('de-notes')};
  else if(deathType==='bugcig')entry={...entry,ship:g('db-ship'),location:g('db-loc'),notes:g('db-notes')};
  data.deaths.unshift(entry);save();updateStats();renderDeaths();
  document.querySelectorAll('#v-deaths input,#v-deaths textarea').forEach(el=>el.value='');
  toast('Death logged');
}
function renderDeaths(){
  const list=document.getElementById('death-list'),q=(document.getElementById('ds-search').value||'').toLowerCase(),tf=document.getElementById('ds-type').value;
  let fil=data.deaths.filter(d=>(!tf||d.dtype===tf)&&(!q||(d.killer||'').toLowerCase().includes(q)||(d.ship||'').toLowerCase().includes(q)||(d.location||'').toLowerCase().includes(q)||(d.notes||'').toLowerCase().includes(q)));
  document.getElementById('death-count').textContent='('+fil.length+' of '+data.deaths.length+')';
  if(!fil.length){list.innerHTML='<div class="empty"><div class="empty-icon">&mdash;</div>'+(data.deaths.length?'NO MATCHES':'NO DEATHS LOGGED YET')+'</div>';return;}
  list.innerHTML=fil.map(d=>{
    const open=expD[d.id],label=DEATH_LABELS[d.dtype]||d.dtype,col=DEATH_COLORS[d.dtype]||'var(--mut)';
    const title=d.killer?`Killed by ${esc(d.killer)}`:(d.ship?`Lost: ${esc(d.ship)}`:label);
    return`<div class="cc death-card"><div class="ch${open?' open':''}" onclick="togD(${d.id})"><div class="ch-l"><span class="xi${open?' open':''}" id="xi-d-${d.id}">&#9658;</span><div><span class="sname" style="color:${col}">${title}</span><div class="cid"><span style="color:${col};opacity:.7">${label}</span>${d.location?' // '+esc(d.location):''}</div></div></div><div class="cm"><span class="cd">${fmtDate(d.date)}</span></div></div>
    <div class="cb${open?' open':''}" id="cb-d-${d.id}"><div class="detail-grid">
    ${d.ship?`<div class="ditem"><span class="dlabel">Ship Lost</span><span class="dval">${esc(d.ship)}</span></div>`:''}
    ${d.killer?`<div class="ditem"><span class="dlabel">Killed By</span><span class="dval" style="color:var(--red)">${esc(d.killer)}</span></div>`:''}
    ${d.killerShip?`<div class="ditem"><span class="dlabel">Their Ship</span><span class="dval">${esc(d.killerShip)}</span></div>`:''}
    ${d.enemy?`<div class="ditem"><span class="dlabel">Enemy</span><span class="dval">${esc(d.enemy)}</span></div>`:''}
    ${d.enemyShip?`<div class="ditem"><span class="dlabel">Enemy Ship</span><span class="dval">${esc(d.enemyShip)}</span></div>`:''}
    ${d.weapon?`<div class="ditem"><span class="dlabel">Weapon</span><span class="dval">${esc(d.weapon)}</span></div>`:''}
    ${d.loadout?`<div class="ditem"><span class="dlabel">Your Loadout</span><span class="dval">${esc(d.loadout)}</span></div>`:''}
    ${d.hit?`<div class="ditem"><span class="dlabel">Hit</span><span class="dval">${esc(d.hit)}</span></div>`:''}
    ${d.hazard?`<div class="ditem"><span class="dlabel">Hazard</span><span class="dval">${esc(d.hazard)}</span></div>`:''}
    ${d.location?`<div class="ditem"><span class="dlabel">Location</span><span class="dval">${esc(d.location)}</span></div>`:''}
    </div>${d.notes?`<div class="sect">// Notes</div><div class="notes-txt">${esc(d.notes)}</div>`:''}<div class="card-actions"><button class="btn-d" onclick="delDeath(${d.id})">Delete</button></div></div></div>`;
  }).join('');
}
function togD(id){expD[id]=!expD[id];const b=document.getElementById('cb-d-'+id),x=document.getElementById('xi-d-'+id);if(b){b.classList.toggle('open',expD[id]);b.previousElementSibling.classList.toggle('open',expD[id]);}if(x)x.classList.toggle('open',expD[id]);}
function delDeath(id){data.deaths=data.deaths.filter(d=>d.id!==id);save();updateStats();renderDeaths();SFX.delete();toast('Death removed');}

// CAREER
function renderCareer(){
  const kills=data.kills.length,deaths=data.deaths.length,kd=deaths>0?(kills/deaths).toFixed(2):kills.toFixed(2);
  document.getElementById('ca-kills').textContent=kills;document.getElementById('ca-deaths').textContent=deaths;document.getElementById('ca-kd').textContent=kd;document.getElementById('ca-caps').textContent=data.captures.length;document.getElementById('ca-profit').textContent=fmtA(calcTotalProfit());
  const mf={};data.kills.forEach(k=>mf[k.method||k.ktype]=(mf[k.method||k.ktype]||0)+1);const ms=Object.entries(mf).sort((a,b)=>b[1]-a[1]);const mm=ms[0]?.[1]||1;
  document.getElementById('ca-methods').innerHTML=ms.length?ms.map(([m,v])=>`<div class="bar-row"><span class="bar-label">${m}</span><div class="bar-track"><div class="bar-fill kill" style="width:${Math.round(v/mm*100)}%"></div></div><span class="bar-val">${v}</span></div>`).join(''):'<div style="color:var(--mut);font-family:var(--mono);font-size:11px;padding:8px 0">No data</div>';
  const sf={};data.kills.filter(k=>k.ship).forEach(k=>sf[k.ship]=(sf[k.ship]||0)+1);const ss=Object.entries(sf).sort((a,b)=>b[1]-a[1]).slice(0,8);const sm=ss[0]?.[1]||1;
  document.getElementById('ca-ships').innerHTML=ss.length?ss.map(([s,v])=>`<div class="bar-row"><span class="bar-label">${esc(s)}</span><div class="bar-track"><div class="bar-fill" style="width:${Math.round(v/sm*100)}%"></div></div><span class="bar-val">${v}</span></div>`).join(''):'<div style="color:var(--mut);font-family:var(--mono);font-size:11px;padding:8px 0">No data</div>';
  const cf={};data.trades.forEach(t=>cf[t.commodity]=(cf[t.commodity]||0)+t.qty);const cs=Object.entries(cf).sort((a,b)=>b[1]-a[1]).slice(0,8);const cm=cs[0]?.[1]||1;
  document.getElementById('ca-commodities').innerHTML=cs.length?cs.map(([c,v])=>`<div class="bar-row"><span class="bar-label">${esc(c)}</span><div class="bar-track"><div class="bar-fill trade" style="width:${Math.round(v/cm*100)}%"></div></div><span class="bar-val">${v} SCU</span></div>`).join(''):'<div style="color:var(--mut);font-family:var(--mono);font-size:11px;padding:8px 0">No data</div>';
  const rf={};data.trades.filter(t=>t.buyLoc&&t.sellLoc&&t.sellPrice>0).forEach(t=>{const k=t.buyLoc+' > '+t.sellLoc;rf[k]=(rf[k]||0)+((t.sellPrice-t.buyPrice)*t.qty);});const rs=Object.entries(rf).sort((a,b)=>b[1]-a[1]).slice(0,6);const rm=rs[0]?.[1]||1;
  document.getElementById('ca-routes').innerHTML=rs.length?rs.map(([r,v])=>`<div class="bar-row"><span class="bar-label">${esc(r)}</span><div class="bar-track"><div class="bar-fill trade" style="width:${Math.round(Math.abs(v)/rm*100)}%"></div></div><span class="bar-val">${fmtA(v)}</span></div>`).join(''):'<div style="color:var(--mut);font-family:var(--mono);font-size:11px;padding:8px 0">No data</div>';
  const df={};data.deaths.forEach(d=>df[DEATH_LABELS[d.dtype]||d.dtype]=(df[DEATH_LABELS[d.dtype]||d.dtype]||0)+1);const ds=Object.entries(df).sort((a,b)=>b[1]-a[1]);const dm=ds[0]?.[1]||1;
  document.getElementById('ca-deaths-chart').innerHTML=ds.length?ds.map(([t,v])=>`<div class="bar-row"><span class="bar-label">${t}</span><div class="bar-track"><div class="bar-fill death" style="width:${Math.round(v/dm*100)}%"></div></div><span class="bar-val">${v}</span></div>`).join(''):'<div style="color:var(--mut);font-family:var(--mono);font-size:11px;padding:8px 0">No data</div>';
  const mmat={};data.mines.forEach(m=>{if(m.material)mmat[m.material]=(mmat[m.material]||0)+(m.yield||0);});const mms=Object.entries(mmat).sort((a,b)=>b[1]-a[1]).slice(0,8);const mmm=mms[0]?.[1]||1;
  document.getElementById('ca-mining').innerHTML=mms.length?mms.map(([m,v])=>`<div class="bar-row"><span class="bar-label">${esc(m)}</span><div class="bar-track"><div class="bar-fill mine" style="width:${Math.round(v/mmm*100)}%"></div></div><span class="bar-val">${v} SCU</span></div>`).join(''):'<div style="color:var(--mut);font-family:var(--mono);font-size:11px;padding:8px 0">No data</div>';
}

// PLAYERS
function submitPlayer(){
  const name=document.getElementById('p-name').value.trim();if(!name){toast('Player name required','err');return;}
  const rsiHandle=document.getElementById('p-rsi').value.trim()||name;
  data.players.unshift({id:Date.now(),name,cat:document.getElementById('p-cat').value,org:document.getElementById('p-org').value.trim(),rsi:rsiHandle,met:document.getElementById('p-met').value.trim(),notes:document.getElementById('p-notes').value.trim(),interactions:[],date:new Date().toISOString()});
  save();updateStats();renderPlayers();['p-name','p-org','p-rsi','p-met','p-notes'].forEach(id=>document.getElementById(id).value='');document.getElementById('p-cat').value='neutral';toast('Contact added');
}
function renderPlayers(){
  const grid=document.getElementById('player-grid'),q=(document.getElementById('ps-search').value||'').toLowerCase(),cf=document.getElementById('ps-cat').value;
  let fil=data.players.filter(p=>(!cf||p.cat===cf)&&(!q||p.name.toLowerCase().includes(q)||(p.met||'').toLowerCase().includes(q)||(p.org||'').toLowerCase().includes(q)));
  if(!fil.length){grid.innerHTML='<div class="empty" style="grid-column:1/-1"><div class="empty-icon">?</div>'+(data.players.length?'NO MATCHES':'NO CONTACTS LOGGED YET')+'</div>';return;}
  grid.innerHTML=fil.map(p=>`<div class="player-card cat-${p.cat}" onclick="openPlayer(${p.id})"><div style="display:flex;align-items:flex-start;justify-content:space-between;gap:8px"><div class="pc-name">${esc(p.name)}</div><span class="pc-cat ${CAT_BADGES[p.cat]||'cat-neutral-b'}">${CAT_LABELS[p.cat]||p.cat}</span></div>${p.org?`<div style="font-size:11px;color:var(--mut);font-family:var(--mono);margin-top:2px">${esc(p.org)}</div>`:''} ${p.met?`<div class="pc-met">${esc(p.met)}</div>`:''}<div class="pc-interactions">${p.interactions.length} log entr${p.interactions.length!==1?'ies':'y'}</div></div>`).join('');
}
function openPlayer(id){
  activePlayer=data.players.find(p=>p.id===id);if(!activePlayer)return;
  document.getElementById('pm-name').textContent=activePlayer.name;
  document.getElementById('pm-org').textContent=activePlayer.org||'';
  const rsiHandle=activePlayer.rsi||activePlayer.name;
  const rsiEl=document.getElementById('pm-rsi-link');
  rsiEl.innerHTML=`<a href="https://robertsspaceindustries.com/citizens/${encodeURIComponent(rsiHandle)}" target="_blank" style="font-family:var(--mono);font-size:10px;color:var(--acc);text-decoration:none;letter-spacing:1px">&#8599; RSI PROFILE</a>`;
  const badge=document.getElementById('pm-cat-badge');badge.textContent=CAT_LABELS[activePlayer.cat]||activePlayer.cat;badge.className='pc-cat '+(CAT_BADGES[activePlayer.cat]||'cat-neutral-b');
  document.getElementById('pm-cat-change').value=activePlayer.cat;
  document.getElementById('pm-notes-edit').value=activePlayer.notes||'';
  renderInteractions();renderPlayerTradeHistory();
  document.getElementById('player-modal').style.display='flex';
}
function renderPlayerTradeHistory(){
  const el=document.getElementById('pm-trade-history');if(!el||!activePlayer)return;
  const name=activePlayer.name.toLowerCase();
  const trades=data.ptrades.filter(t=>(t.buyFrom||'').toLowerCase()===name||(t.soldTo||'').toLowerCase()===name);
  if(!trades.length){el.innerHTML='';return;}
  el.innerHTML=`<div style="background:var(--card);border:1px solid var(--brd);border-radius:var(--radius);padding:10px 12px;margin-bottom:10px"><div style="font-family:var(--mono);font-size:10px;color:var(--acc);letter-spacing:2px;margin-bottom:8px">// TRADE HISTORY (${trades.length})</div>${trades.map(t=>`<div style="display:flex;justify-content:space-between;font-size:12px;padding:3px 0;border-bottom:1px solid var(--brd)"><span style="color:var(--txt)">${esc(t.item)}</span><span style="font-family:var(--mono);color:${(t.buyFrom||'').toLowerCase()===name?'var(--amber)':'var(--grn)'}">${(t.buyFrom||'').toLowerCase()===name?'Bought from':'Sold to'}</span><span style="font-family:var(--mono);color:var(--mut)">${t.sellPrice||t.buyPrice?fmtA(t.sellPrice||t.buyPrice)+' aUEC':''}</span></div>`).join('')}</div>`;
}
function renderInteractions(){
  const el=document.getElementById('pm-interactions');
  if(!activePlayer.interactions.length){el.innerHTML='<div style="color:var(--mut);font-family:var(--mono);font-size:11px;padding:8px 0;text-align:center">No contact log entries yet</div>';return;}
  el.innerHTML=[...activePlayer.interactions].reverse().map((i,ri)=>{const realIdx=activePlayer.interactions.length-1-ri;return`<div class="interaction-entry"><div class="ie-date">${fmtDate(i.date)}</div><div class="ie-note">${esc(i.note)}</div><div style="margin-top:6px"><button class="btn-d" style="font-size:10px;padding:3px 8px" onclick="delInteraction(${realIdx})">Delete</button></div></div>`;}).join('');
}
function savePlayerNotes(){if(!activePlayer)return;activePlayer.notes=document.getElementById('pm-notes-edit').value;save();toast('Notes saved');}
function addInteraction(){const note=document.getElementById('pm-new-interaction').value.trim();if(!note||!activePlayer)return;activePlayer.interactions.push({note,date:new Date().toISOString()});save();renderInteractions();renderPlayers();document.getElementById('pm-new-interaction').value='';toast('Contact logged');}
function delInteraction(idx){activePlayer.interactions.splice(idx,1);save();renderInteractions();renderPlayers();toast('Entry removed');}
function updatePlayerCat(){if(!activePlayer)return;activePlayer.cat=document.getElementById('pm-cat-change').value;save();renderPlayers();openPlayer(activePlayer.id);toast('Classification updated');}
function deletePlayer(){if(!activePlayer)return;data.players=data.players.filter(p=>p.id!==activePlayer.id);save();updateStats();renderPlayers();closePlayerModal();SFX.delete();toast('Contact removed');}
function closePlayerModal(e){if(e&&e.target!==document.getElementById('player-modal'))return;document.getElementById('player-modal').style.display='none';activePlayer=null;}

// SETTINGS
function openSettings(){
  const s=data.settings;
  document.getElementById('set-orgname').value=s.orgname||"Captain's Log";
  document.getElementById('set-subtitle').value=s.subtitle||'Personal Tracker';
  document.getElementById('set-handle').value=s.handle||'';
  document.getElementById('set-tbtitle').value=s.tbtitle||"CAPTAIN'S LOG";
  // Logo fields
  const defs={bg:'#060d1a',surf:'#0a1428',card:'#0e1c36',brd:'#1a3060',acc:'#4488dd',acc2:'#66aaff',accd:'#1a4488',txt:'#e8f0ff',mut:'#507090'};
  const logoFill=document.getElementById('col-logo-fill');
  const logoBorder=document.getElementById('col-logo-border');
  const logoInitials=document.getElementById('set-logo-initials');
  if(logoFill)logoFill.value=s.logoFill||s.accd||'#1a3a6a';
  if(logoBorder)logoBorder.value=s.logoBorder||s.acc||'#4488dd';
  if(logoInitials)logoInitials.value=s.logoInitials||'CS';
  // Show current logo in preview
  const pImg=document.getElementById('logo-preview-img');
  const pIni=document.getElementById('logo-preview-initials');
  const pBox=document.getElementById('logo-preview-box');
  if(pBox){pBox.style.background=s.logoFill||s.accd||'#1a3a6a';pBox.style.borderColor=s.logoBorder||s.acc||'#4488dd';}
  if(s.orgLogo&&pImg){pImg.src=s.orgLogo;pImg.style.display='';if(pIni)pIni.style.display='none';}
  else{if(pImg){pImg.src='';pImg.style.display='none';}if(pIni){pIni.textContent=(s.logoInitials||'CS').toUpperCase();pIni.style.color=s.logoBorder||s.acc||'#4488dd';pIni.style.display='';}}
  window._pendingLogo=undefined;
  Object.entries(defs).forEach(([k,def])=>{const el=document.getElementById('col-'+k);if(el){el.value=s[k]||def;const vEl=document.getElementById('col-'+k+'-val');if(vEl)vEl.textContent=s[k]||def;}});
  renderSavedThemes();livePreview();
  document.getElementById('settings-overlay').style.display='flex';
}
function saveSettings(){
  data.settings={...data.settings,
    orgname:document.getElementById('set-orgname').value.trim(),
    subtitle:document.getElementById('set-subtitle').value.trim(),
    handle:document.getElementById('set-handle').value.trim(),
    tbtitle:document.getElementById('set-tbtitle').value.trim(),
    logoFill:window._pendingLogoFill||document.getElementById('col-logo-fill')?.value||data.settings.logoFill,
    logoBorder:window._pendingLogoBorder||document.getElementById('col-logo-border')?.value||data.settings.logoBorder,
    logoInitials:(window._pendingLogoInitials||document.getElementById('set-logo-initials')?.value||'CS').toUpperCase(),
    orgLogo:window._pendingLogo!==undefined?window._pendingLogo:data.settings.orgLogo,
    bg:document.getElementById('col-bg').value,surf:document.getElementById('col-surf').value,
    card:document.getElementById('col-card').value,brd:document.getElementById('col-brd').value,
    acc:document.getElementById('col-acc').value,acc2:document.getElementById('col-acc2').value,
    accd:document.getElementById('col-accd').value,txt:document.getElementById('col-txt').value,
    mut:document.getElementById('col-mut').value,
    theme:window._pendingTheme||data.settings.theme||{},
    factiontag:window._pendingFactionTag||data.settings.factiontag||''
  };
  window._pendingTheme=null;window._pendingFactionTag=null;window._pendingLogo=undefined;
  window._pendingLogoFill=null;window._pendingLogoBorder=null;window._pendingLogoInitials=null;
  save();applyTheme();applyLogoToDOM();closeSettings();toast('Settings saved');
}
function resetTheme(){
  const d=DEFAULT_CL_THEME;
  Object.entries(d.c).forEach(([k,v])=>{data.settings[k]=v;});
  data.settings.theme={...d.th};
  data.settings.factiontag=d.tag;
  data.settings.orgname=d.name;
  data.settings.subtitle=d.sub;
  data.settings.tbtitle="CAPTAIN'S LOG";
  data.settings.logoFill=null;
  data.settings.logoBorder=null;
  data.settings.logoInitials='CS';
  save();applyTheme();applyLogoToDOM();closeSettings();toast('Theme reset to default');
}
function closeSettings(e){if(e&&e.target!==document.getElementById('settings-overlay'))return;document.getElementById('settings-overlay').style.display='none';}
function toast(msg,type){const t=document.getElementById('toast');t.textContent=msg;t.className='toast show'+(type?' '+type:'');setTimeout(()=>t.className='toast',2500);if(type==='err'||type==='warn')SFX.error();else SFX.confirm();}


// MATERIAL HINT
function matHint(prefix){
  const val=document.getElementById(prefix+'-mat')?.value||'';
  const match=Object.entries(MINING_DATA).find(([k])=>k.toLowerCase()===val.toLowerCase());
  if(match){
    const [name,mdata]=match;
    // Auto-set mining type
    const typeMap={ship:'ship',hand:'hand',ground:'ground'};
    if(typeMap[mdata.type]){setMineType(mdata.type);}
    // Fill location hint
    const locEl=document.getElementById(prefix+'-loc');
    if(locEl&&!locEl.value)locEl.placeholder='e.g. '+mdata.locations.split(',')[0].trim()+'...';
    // Show hint
    const hintEl=document.getElementById(prefix+'-hint');
    if(hintEl)hintEl.textContent='Found: '+mdata.locations;
  }
}

