// MATERIAL AUTOCOMPLETE with hints
function acMaterial(inputId,listId,prefix){
  const inp=document.getElementById(inputId);
  const list=document.getElementById(listId);
  if(!inp||!list)return;
  const val=inp.value.toLowerCase();
  if(!val){list.classList.remove('open');return;}
  const matches=Object.keys(MINING_DATA).filter(k=>k.toLowerCase().includes(val)).slice(0,10);
  if(!matches.length){list.classList.remove('open');return;}
  list.innerHTML=matches.map(m=>{
    const d=MINING_DATA[m];
    return`<div class="ac-item"><div>${m}</div><div style="font-size:10px;color:var(--mut);font-family:var(--mono)">${d.type} — ${d.locations.length>50?d.locations.slice(0,50)+'...':d.locations}</div></div>`;
  }).join('');
  list.classList.add('open');
  list.querySelectorAll('.ac-item').forEach((el,idx)=>{
    el.addEventListener('mousedown',e=>e.preventDefault());
    el.addEventListener('click',function(){
      const name=matches[idx];
      inp.value=name;
      list.classList.remove('open');
      const d=MINING_DATA[name];
      if(d){
        const locEl=document.getElementById(prefix+'-loc');
        if(locEl&&!locEl.value)locEl.placeholder=d.locations.split(',')[0].trim()+'...';
        const hintEl=document.getElementById(prefix+'-hint');
        if(hintEl)hintEl.textContent='Found in: '+d.locations+(d.locations.includes('Rare')?' ⚠ Rare':'');
      }
      inp.focus();
    });
  });
}

// HARVESTING HINT
function hvHint(prefix){
  if(prefix==='hv'){
    const inp=document.getElementById('hv-item');
    const list=document.getElementById('hv-ac');
    if(!inp||!list)return;
    const val=inp.value.toLowerCase();
    if(!val){list.classList.remove('open');document.getElementById('hv-hint').textContent='';return;}
    const matches=Object.keys(HARVESTABLES_DATA).filter(k=>k.toLowerCase().includes(val)).slice(0,8);
    if(!matches.length){list.classList.remove('open');return;}
    list.innerHTML=matches.map(m=>{
      const d=HARVESTABLES_DATA[m];
      return`<div class="ac-item"><div>${m}</div><div style="font-size:10px;color:var(--mut);font-family:var(--mono)">${d.locations.length>50?d.locations.slice(0,50)+'...':d.locations}</div></div>`;
    }).join('');
    list.classList.add('open');
    list.querySelectorAll('.ac-item').forEach((el,idx)=>{
      el.addEventListener('mousedown',e=>e.preventDefault());
      el.addEventListener('click',function(){
        const name=matches[idx];
        inp.value=name;
        list.classList.remove('open');
        const d=HARVESTABLES_DATA[name];
        if(d){
          const locEl=document.getElementById('hv-loc');
          if(locEl&&!locEl.value)locEl.placeholder=d.locations.split(',')[0].trim()+'...';
          const hintEl=document.getElementById('hv-hint');
          if(hintEl)hintEl.textContent='Found in: '+d.locations;
        }
        inp.focus();
      });
    });
  } else {
    const inp=document.getElementById('hv-creature');
    const list=document.getElementById('creature-ac');
    if(!inp||!list)return;
    const val=inp.value.toLowerCase();
    if(!val){list.classList.remove('open');document.getElementById('creature-hint').textContent='';return;}
    const matches=Object.keys(CREATURES_DATA).filter(k=>k.toLowerCase().includes(val)).slice(0,8);
    if(!matches.length){list.classList.remove('open');return;}
    list.innerHTML=matches.map(m=>{
      const d=CREATURES_DATA[m];
      return`<div class="ac-item"><div>${m}</div><div style="font-size:10px;color:var(--mut);font-family:var(--mono)">${d.chance} — ${d.locations.length>50?d.locations.slice(0,50)+'...':d.locations}</div></div>`;
    }).join('');
    list.classList.add('open');
    list.querySelectorAll('.ac-item').forEach((el,idx)=>{
      el.addEventListener('mousedown',e=>e.preventDefault());
      el.addEventListener('click',function(){
        const name=matches[idx];
        inp.value=name;
        list.classList.remove('open');
        const d=CREATURES_DATA[name];
        if(d){
          const locEl=document.getElementById('hv-cloc');
          if(locEl&&!locEl.value)locEl.placeholder=d.locations.split(',')[0].trim()+'...';
          const hintEl=document.getElementById('creature-hint');
          if(hintEl)hintEl.textContent='Found in: '+d.locations;
        }
        inp.focus();
      });
    });
  }
}

// SUBMIT HARVEST
function submitHarvest(htype){
  let entry={id:Date.now(),htype,date:new Date().toISOString()};
  if(htype==='plant'){
    const item=document.getElementById('hv-item').value.trim();if(!item){toast('Item name required','err');return;}
    entry={...entry,item,qty:parseFloat(document.getElementById('hv-qty').value)||0,location:document.getElementById('hv-loc').value.trim()||document.getElementById('hv-loc').placeholder.replace('...',''),notes:document.getElementById('hv-notes').value.trim()};
    ['hv-item','hv-qty','hv-loc','hv-notes'].forEach(id=>{const el=document.getElementById(id);if(el){el.value='';el.placeholder=el.id==='hv-loc'?'Auto-filled or override...':'';}});
    document.getElementById('hv-hint').textContent='';
  } else {
    const creature=document.getElementById('hv-creature').value.trim();if(!creature){toast('Creature name required','err');return;}
    entry={...entry,item:creature,qty:parseFloat(document.getElementById('hv-cqty').value)||0,location:document.getElementById('hv-cloc').value.trim()||document.getElementById('hv-cloc').placeholder.replace('...',''),notes:document.getElementById('hv-cnotes').value.trim()};
    ['hv-creature','hv-cqty','hv-cloc','hv-cnotes'].forEach(id=>{const el=document.getElementById(id);if(el){el.value='';el.placeholder=el.id==='hv-cloc'?'Auto-filled or override...':'';}});
    document.getElementById('creature-hint').textContent='';
  }
  data.harvests.unshift(entry);save();renderHarvests();toast(htype==='plant'?'Harvest logged':'Encounter logged');
}

