function togH(id){expH[id]=!expH[id];const b=document.getElementById('cb-h-'+id),x=document.getElementById('xi-h-'+id);if(b){b.classList.toggle('open',expH[id]);b.previousElementSibling.classList.toggle('open',expH[id]);}if(x)x.classList.toggle('open',expH[id]);}
