// ── SORT HELPERS ──────────────────────────────────────────────────────────────
function applySortUI(prefix,key,dir,keys){
  keys.forEach(k=>{const el=document.getElementById(prefix+'-s'+k);if(el)el.classList.toggle('active',k===key);});
  const dirEl=document.getElementById(prefix+'-dir');
  if(dirEl)dirEl.textContent=dir===-1?'↓ Newest':'↑ Oldest';
}

// KILLS sort
function setKillSort(k){killSort.key=k;renderKills();}
function toggleKillDir(){killSort.dir*=-1;renderKills();}

// CAPTURES sort
function setCapSort(k){capSort.key=k;renderCaptures();}
function toggleCapDir(){capSort.dir*=-1;renderCaptures();}

// DEATHS sort
function setDeathSort(k){deathSort.key=k;renderDeaths();}
function toggleDeathDir(){deathSort.dir*=-1;renderDeaths();}

// PLAYERS sort
function setPlayerSort(k){playerSort.key=k;renderPlayers();}
function togglePlayerDir(){playerSort.dir*=-1;renderPlayers();}

// BOUNTIES sort
function setBountySort(k){bountySort.key=k;renderBounties();}
function toggleBountyDir(){bountySort.dir*=-1;renderBounties();}

function sortArr(arr,sort){
  return [...arr].sort((a,b)=>{
    let av,bv;
    if(sort.key==='date'){av=a.date||'';bv=b.date||'';}
    else if(sort.key==='pilot'){av=(a.pilot||'').toLowerCase();bv=(b.pilot||'').toLowerCase();}
    else if(sort.key==='ship'){av=(a.ship||'').toLowerCase();bv=(b.ship||'').toLowerCase();}
    else if(sort.key==='name'){av=(a.name||'').toLowerCase();bv=(b.name||'').toLowerCase();}
    else if(sort.key==='cat'){const o={orgmate:0,trusted:1,friendly:2,neutral:3,hostile:4,highthreat:5};av=o[a.cat]??3;bv=o[b.cat]??3;}
    else if(sort.key==='cause'){av=a.dtype||'';bv=b.dtype||'';}
    else if(sort.key==='outcome'){av=a.success||'';bv=b.success||'';}
    else if(sort.key==='value'){av=a.value||0;bv=b.value||0;}
    else if(sort.key==='target'){av=(a.target||'').toLowerCase();bv=(b.target||'').toLowerCase();}
    else if(sort.key==='status'){av=a.status||'';bv=b.status||'';}
    else{av=a.date||'';bv=b.date||'';}
    if(av<bv)return -1*sort.dir;
    if(av>bv)return 1*sort.dir;
    return 0;
  });
}

// ── BOUNTIES ──────────────────────────────────────────────────────────────────
const BOUNTY_TYPE_LABELS={crimestat:'Crimestat',assassination:'Assassination',retrieval:'Retrieval',delivery:'Delivery Intercept',other:'Other'};
const BOUNTY_STATUS_CLASSES={active:'bounty-active',complete:'bounty-complete',failed:'bounty-failed'};

function submitBounty(){
  const target=document.getElementById('bq-target').value.trim();
  if(!target){toast('Target name required','err');return;}
  const entry={
    id:Date.now(),
    target,
    value:parseFloat(document.getElementById('bq-value').value)||100000,
    targetShip:document.getElementById('bq-targetship').value.trim(),
    yourShip:document.getElementById('bq-yourship').value.trim(),
    location:document.getElementById('bq-loc').value.trim(),
    status:document.getElementById('bq-status').value,
    notes:document.getElementById('bq-notes').value.trim(),
    date:new Date().toISOString()
  };
  data.bounties.unshift(entry);save();renderBounties();
  ['bq-target','bq-targetship','bq-yourship','bq-loc','bq-notes'].forEach(id=>document.getElementById(id).value='');
  document.getElementById('bq-value').value='100000';
  document.getElementById('bq-status').value='active';
  toast('Bounty logged');
}

function renderBounties(){
  const list=document.getElementById('bounty-list');
  const q=(document.getElementById('bqs-search')?.value||'').toLowerCase();
  const sf=document.getElementById('bqs-status')?.value||'';
  let fil=(data.bounties||[]).filter(b=>{
    return(!sf||b.status===sf)&&
      (!q||(b.target||'').toLowerCase().includes(q)||(b.location||'').toLowerCase().includes(q)||(b.targetShip||'').toLowerCase().includes(q));
  });
  fil=sortArr(fil,bountySort);
  applySortUI('bqs',bountySort.key,bountySort.dir,['date','value','target','status']);
  // Update summary
  const allB=data.bounties||[];
  const earned=allB.filter(b=>b.status==='complete').reduce((s,b)=>s+(b.value||0),0);
  const active=allB.filter(b=>b.status==='active').length;
  const tc=document.getElementById('bq-total-count');if(tc)tc.textContent=allB.length;
  const te=document.getElementById('bq-total-earned');if(te)te.textContent=fmtA(earned);
  const ac=document.getElementById('bq-active-count');if(ac)ac.textContent=active;
  document.getElementById('bounty-count').textContent='('+fil.length+' of '+allB.length+')';
  if(!fil.length){list.innerHTML='<div class="empty"><div class="empty-icon">&#9654;</div>'+(allB.length?'NO MATCHES':'NO BOUNTIES LOGGED YET')+'</div>';return;}
  list.innerHTML=fil.map(b=>{
    const open=expBQ[b.id];
    const stClass=BOUNTY_STATUS_CLASSES[b.status]||'bounty-active';
    return`<div class="cc bounty-card"><div class="ch${open?' open':''}" onclick="togBQ(${b.id})"><div class="ch-l"><span class="xi${open?' open':''}" id="xi-bq-${b.id}">&#9658;</span><div style="min-width:0"><div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap"><span class="sname bounty-name">${esc(b.target)}</span><span class="cbadge ${stClass}">${b.status}</span>${b.value?`<span style="font-family:var(--mono);font-size:10px;color:var(--grn)">${fmtA(b.value)} aUEC</span>`:''}</div><div class="cid">${b.location?esc(b.location):''}${b.targetShip?' // '+esc(b.targetShip):''}</div></div></div><div class="cm"><span class="cd">${fmtDate(b.date)}</span></div></div>
    <div class="cb${open?' open':''}" id="cb-bq-${b.id}"><div class="detail-grid">
    <div class="ditem"><span class="dlabel">Target</span><span class="dval" style="color:#c060ff">${esc(b.target)}</span></div>
    <div class="ditem"><span class="dlabel">Value</span><span class="dval" style="color:var(--grn)">${b.value?fmtA(b.value)+' aUEC':'—'}</span></div>
    <div class="ditem"><span class="dlabel">Status</span><span class="dval"><span class="cbadge ${stClass}">${b.status}</span></span></div>
    ${b.targetShip?`<div class="ditem"><span class="dlabel">Their Ship</span><span class="dval">${esc(b.targetShip)}</span></div>`:''}
    ${b.yourShip?`<div class="ditem"><span class="dlabel">Your Ship</span><span class="dval">${esc(b.yourShip)}</span></div>`:''}
    ${b.location?`<div class="ditem"><span class="dlabel">Location</span><span class="dval">${esc(b.location)}</span></div>`:''}
    </div>${b.notes?`<div class="sect">// Notes</div><div class="notes-txt">${esc(b.notes)}</div>`:''}<div class="card-actions">
    ${b.status==='active'?`<button class="btn-s" onclick="completeBounty(${b.id})">Mark Complete</button><button class="btn-s" style="border-color:var(--red);color:var(--red)" onclick="failBounty(${b.id})">Mark Failed</button>`:''}
    <button class="btn-d" onclick="delBounty(${b.id})">Delete</button></div></div></div>`;
  }).join('');
}

function togBQ(id){expBQ[id]=!expBQ[id];const b=document.getElementById('cb-bq-'+id),x=document.getElementById('xi-bq-'+id);if(b){b.classList.toggle('open',expBQ[id]);b.previousElementSibling.classList.toggle('open',expBQ[id]);}if(x)x.classList.toggle('open',expBQ[id]);}
function completeBounty(id){
  const b=data.bounties.find(x=>x.id===id);
  if(b){
    b.status='complete';
    // Auto-log a kill from bounty data
    const killEntry={
      id:Date.now(),
      ktype:'ship',
      date:new Date().toISOString(),
      pilot:b.target||'',
      org:'',
      ship:b.targetShip||'',
      shipClass:'Unknown',
      method:'Bounty',
      location:b.location||'',
      notes:'Auto-logged from bounty completion'+(b.notes?': '+b.notes:''),
      yourShip:b.yourShip||''
    };
    data.kills.unshift(killEntry);
    save();updateStats();renderBounties();renderKills();
    SFX.complete();
    toast('Bounty complete — kill logged');
  }
}
function failBounty(id){const b=data.bounties.find(x=>x.id===id);if(b){b.status='failed';save();renderBounties();toast('Bounty marked failed','warn');}}
function delBounty(id){data.bounties=data.bounties.filter(b=>b.id!==id);save();renderBounties();SFX.delete();toast('Bounty removed');}

